def is_distinct(n):
    unique_digits = set()
    while n > 0:
        digit = n % 10
        if digit in unique_digits:
            return False
        unique_digits.add(digit)
        n //= 10
    return True

def count_special(n):
    count = 0
    for i in range(1, n + 1):
        if is_distinct(i):
            count += 1
    return count
```

