function isDistinct(n) {
    const uniqueDigits = new Set();
    while (n > 0) {
        const digit = n % 10;
        if (uniqueDigits.has(digit)) {
            return false;
        }
        uniqueDigits.add(digit);
        n = Math.floor(n / 10);
    }
    return true;
}

function countSpecial(n) {
    let count = 0;
    for (let i = 1; i <= n; i++) {
        if (isDistinct(i)) {
            count++;
        }
    }
    return count;
}
